async def __get_secure_creds(self, ca_cert, cert_key=None, cert_cert=None):
    @override
    async def read_file(fn):
        if fn is None:
            return None
        with aiofiles.open(fn, 'rb') as f:
            return await f.read()

    assert ca_cert is not None
