import abc

class Base(abc.ABC):
    @abc.abstractmethod
    def abstract(self):
        pass

# doesn't implement the contract as you'd like ...
class Impl(Base):
    def abstract(self, first_param, second_param):
        print(self)

# ... but can be instantiated and runs...
i = Impl()
i.abstract(1, 2)
# >>> sneaking one past the goalie
